import{_ as a,o as t,c as s,j as r,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"基础武学-身法","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/武学基础/基础武学-身法.md","filePath":"4.资源分区/6.技艺及称号/武技类/武学基础/基础武学-身法.md"}'),p={name:"4.资源分区/6.技艺及称号/武技类/武学基础/基础武学-身法.md"};function d(_,e,b,l,i,c){return t(),s("div",null,[...e[0]||(e[0]=[r("h1",{id:"基础武学-身法",tabindex:"-1"},[n("基础武学-身法 "),r("a",{class:"header-anchor",href:"#基础武学-身法","aria-label":'Permalink to "基础武学-身法"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001")])])],-1),o('<h1 id="基础武学-身法-1" tabindex="-1">基础武学-身法 <a class="header-anchor" href="#基础武学-身法-1" aria-label="Permalink to &quot;基础武学-身法&quot;">​</a></h1><p>基础武学-身法<br> 江湖中最最基础的武功招法，在结合不同的基本功和兵器招式之后，大囧朝廷通过总结推演出新，创新性的为百姓和天下所有武学新人创造了这些更接近于实战的基础武功，并划分江南漠北地区二十八县推广推陈，力求普及，为未来扫平江湖提前埋下另一道伏笔。</p><p>本系列下所有能力皆需要内力能量池才可购买。<br> 特殊的，许多侠客因为奇遇而习练得轻功之法，如果st同意，本系列身法D和C阶段无需逐级购买。</p><p>基础功 500<br> 学习轻功之前，宜先练基础功——丹田内功。<br> 如今的人，身体虽强弱各异，但若未经过气功锻炼，大多上焦满蚀，下焦虚陷，气机紊乱，意气不和。丹田内功就是以特定的方法锻炼人身三宝精、气、神，使百脉通畅，丹田之气充盈。<br> 晋代许逊在《灵剑子》中云：“气若功成，筋骨和柔，百关调畅。”<br> 丹田内功性命双修，这里为轻功基础，修好命功阶段即可。<br> 在这个阶段下，当你的内力能量池不为空时，可以获得无需呼吸的能力，视为使用者运转内力进行内丹田的循环调息。并且拥有等于基础移动速度的水面移动速度，视为一种水上漂行为，但是移动结束后需要到达可站立地面之上。</p><p>轻功入门 D+1000<br> 习练轻功，特别强调循序渐进的原则，从最基础处起步，由易到难，由浅而深，老老实实地按步骤进行，不能擅自跨越某一练功步骤，此其一；其二，每日练功，在强度上也要注意循序渐进，不要急于求成，一口吃一个胖子，不顾自己身体的承受程度而接命加大练功量。贪功冒进往往损伤身体而练一日养十日，欲速反而不达。循序渐进，是每个练功者要时时把握的一大原则。<br> 轻功初级功由跑步、跑桩、跑砖、顶功几个练功层次组成，其目的在于锻炼脚步的轻稳和身体的浮劲。<br> 轻稳：当你的内力池不为空时，你的潜行行走速度取消行走速度限制<br> 浮劲：花费一个标准动作消耗2内力，当你进行移动之时，可以使用双腿奔跑在空中进行移动或借助可供踩踏的事物借力进行空中移动，这视为具有了一种类普通级飞行的能力</p><p>轻功中级C+1000<br> 我们经过对各门派、各种练功方法的进一步考察，并结合前人练功的成功经验，将轻功中级阶段的功夫概括为“飞檐走壁”和“踏雪无痕”两大类。前者为向上跳跃之法，后者为平行奔走如草上飞、<br> 雪上飘、水上行等之法。每类之下，各选最稳妥有效的练习方法若干项，并说明其练习的先后次序，使学习者有章可循，有法可参，不至于苦自摸索而走入歧途，徒费许多时间和精力<br> 飞檐走壁：当你的内力能量池不为空时，你无需再花费标准动作和内力，当你进行移动之时，可以使用双腿奔跑在空中进行移动或借助可供踩踏的事物借力进行空中移动，<br> 踏雪无痕：你的移动速度额外增加25米，并且从现在开始你可以站立在水面之上，无需受到基本功的移动结束必须站立在实地上的限制。</p><p>施展此页面技艺都是一种移动技。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(p,[["render",d]]);export{f as __pageData,m as default};
